args.content:
/**
 * script.js - 计算器核心逻辑
 * 
 * 包含：状态模型、计算引擎、状态管理、精度修正
 * DOM 交互部分由 TASK-004 完善
 * 
 * 关联需求：REQ-F001~F005, REQ-F007, REQ-F008, REQ-NF004
 */

// ============================================================
// 状态模型（design.md §4.1, §4.2）
// ============================================================

/**
 * 计算器初始状态
 * 
 * displayValue: 当前显示值（字符串）
 * firstOperand: 第一个操作数（数值或 null）
 * operator: 当前运算符（'+', '-', '×', '÷' 或 null）
 * waitingForSecondOperand: 是否等待输入第二个操作数
 * lastResult: 上一次计算结果（用于连续按等号重复运算）
 * lastOperator: 上一次使用的运算符
 * lastSecondOperand: 上一次的第二个操作数
 * isError: 是否处于错误状态（如除零错误）
 */
var INITIAL_STATE = {
  displayValue: '0',
  firstOperand: null,
  operator: null,
  waitingForSecondOperand: false,
  lastResult: null,
  lastOperator: null,
  lastSecondOperand: null,
  isError: false
};

// 当前计算器状态（由 init() 初始化）
var state = null;

// ============================================================
// 计算引擎（design.md §6.2.3）
// ============================================================

/**
 * 执行四则运算
 * 
 * @param {number} firstOperand - 第一个操作数
 * @param {number} secondOperand - 第二个操作数
 * @param {string} operator - 运算符（'+', '-', '×', '÷'）
 * @returns {number|null} 计算结果；除数为零时返回 null
 * 
 * 关联需求：REQ-F001（加法）, REQ-F002（减法）, REQ-F003（乘法）, REQ-F004（除法）, REQ-F005（除零）
 */
function calculate(firstOperand, secondOperand, operator) {
  switch (operator) {
    case '+':
      return firstOperand + secondOperand;
    case '-':
      return firstOperand - secondOperand;
    case '×':
      return firstOperand * secondOperand;
    case '÷':
      if (secondOperand === 0) {
        return null; // 除零检测（REQ-F005）
      }
      return firstOperand / secondOperand;
    default:
      return secondOperand;
  }
}

// ============================================================
// 浮点精度修正（design.md §5.3）
// ============================================================

/**
 * 浮点精度修正函数
 * 
 * 策略：
 * 1. 使用 toFixed(10) 将结果固定为 10 位小数
 * 2. 去除末尾多余的零
 * 3. 处理 !isFinite() 特殊值，返回 '错误'
 * 
 * 关联需求：REQ-NF004（计算精度）
 * 
 * @param {number} value - 需要修正的数值
 * @returns {string} 修正后的字符串表示
 */
function fixPrecision(value) {
  if (!isFinite(value)) {
    return '错误';
  }
  // 使用 toFixed(10) 解决 IEEE 754 浮点精度问题
  var fixed = value.toFixed(10);
  // 去除末尾多余的零（如 '3.0000000000' → '3', '0.3000000000' → '0.3'）
  var trimmed = fixed.replace(/\.?0+$/, '');
  return trimmed;
}

// ============================================================
// 状态管理核心函数（design.md §6.2.2）
// ============================================================

/**
 * 状态机入口：根据 action 类型分发到对应处理函数
 * 
 * @param {Object} currentState - 当前计算器状态
 * @param {Object} action - 操作对象，包含 type 和可能的参数
 * @returns {Object} 新的计算器状态
 * 
 * 关联需求：REQ-F001~F008, REQ-F005
 */
function handleAction(currentState, action) {
  // 错误状态下，只有 CLEAR 操作可解除（design.md §5.4）
  if (currentState.isError && action.type !== 'CLEAR') {
    return currentState;
  }

  switch (action.type) {
    case 'DIGIT':
      return inputDigit(currentState, action.value);
    case 'OPERATOR':
      return handleOperator(currentState, action.operator);
    case 'EQUALS':
      return handleEquals(currentState);
    case 'CLEAR':
      return handleClear();
    case 'NEGATE':
      return handleNegate(currentState);
    case 'PERCENT':
      return handlePercent(currentState);
    default:
      return currentState;
  }
}

/**
 * 处理数字按钮输入
 * 
 * 约束：
 * - 同一数字中不得出现两个小数点（REQ-F006 AC-F006-4）
 * - 连续输入数字时追加到显示值（REQ-F006 AC-F006-3）
 * - waitingForSecondOperand 时替换显示值
 * 
 * @param {Object} currentState - 当前状态
 * @param {string} digit - 数字字符（'0'-'9' 或 '.'）
 * @returns {Object} 新状态
 */
function inputDigit(currentState, digit) {
  // 如果正在等待第二个操作数，替换显示值
  if (currentState.waitingForSecondOperand) {
    if (digit === '.') {
      return Object.assign({}, currentState, {
        displayValue: '0.',
        waitingForSecondOperand: false
      });
    }
    return Object.assign({}, currentState, {
      displayValue: digit,
      waitingForSecondOperand: false
    });
  }

  // 防止重复小数点
  if (digit === '.' && currentState.displayValue.indexOf('.') !== -1) {
    return currentState;
  }

  // 当前显示为 '0' 且输入不是小数点时，替换而非追加
  if (currentState.displayValue === '0' && digit !== '.') {
    return Object.assign({}, currentState, {
      displayValue: digit
    });
  }

  // 追加数字
  return Object.assign({}, currentState, {
    displayValue: currentState.displayValue + digit
  });
}

/**
 * 处理运算符按钮输入
 * 
 * 行为：
 * - 若已有第一操作数和运算符且正在输入第二操作数，先计算中间结果
 * - 存储运算符，进入等待第二操作数状态
 * 
 * @param {Object} currentState - 当前状态
 * @param {string} nextOperator - 运算符
 * @returns {Object} 新状态
 */
function handleOperator(currentState, nextOperator) {
  var currentValue = parseFloat(currentState.displayValue);

  // 如果已有运算符且不在等待状态（即已输入第二操作数），先计算中间结果
  if (currentState.operator && !currentState.waitingForSecondOperand) {
    var result = calculate(currentState.firstOperand, currentValue, currentState.operator);
    if (result === null) {
      // 除零错误
      return Object.assign({}, INITIAL_STATE, {
        displayValue: '错误',
        isError: true
      });
    }
    var displayValue = fixPrecision(result);
    return Object.assign({}, currentState, {
      displayValue: displayValue,
      firstOperand: result,
      operator: nextOperator,
      waitingForSecondOperand: true,
      lastResult: null,
      lastOperator: null,
      lastSecondOperand: null
    });
  }

  // 存储运算符，以当前显示值作为第一操作数
  return Object.assign({}, currentState, {
    firstOperand: currentValue,
    operator: nextOperator,
    waitingForSecondOperand: true,
    lastResult: null,
    lastOperator: null,
    lastSecondOperand: null
  });
}

/**
 * 处理等号按钮
 * 
 * 行为：
 * - 若有完整的表达式（第一操作数 + 运算符 + 第二操作数），执行计算
 * - 若缺少第二操作数，保持当前显示（REQ-F008 AC-F008-2）
 * - 支持连续按等号重复运算
 * 
 * @param {Object} currentState - 当前状态
 * @returns {Object} 新状态
 */
function handleEquals(currentState) {
  var secondOperand;
  var operator;

  if (currentState.waitingForSecondOperand) {
    // 没有输入第二操作数，保持当前显示
    if (currentState.lastResult === null) {
      return currentState;
    }
    // 连续按等号：使用上次的运算符和第二操作数重复运算
    return currentState;
  }

  if (currentState.firstOperand !== null && currentState.operator) {
    // 正常计算
    secondOperand = parseFloat(currentState.displayValue);
    operator = currentState.operator;

    var result = calculate(currentState.firstOperand, secondOperand, operator);
    if (result === null) {
      // 除零错误
      return Object.assign({}, INITIAL_STATE, {
        displayValue: '错误',
        isError: true
      });
    }

    var displayValue = fixPrecision(result);
    return Object.assign({}, INITIAL_STATE, {
      displayValue: displayValue,
      lastResult: result,
      lastOperator: operator,
      lastSecondOperand: secondOperand
    });
  }

  // 没有运算符，检查是否有上次的重复运算信息
  if (currentState.lastOperator && currentState.lastSecondOperand !== null) {
    var currentVal = parseFloat(currentState.displayValue);
    var repeatResult = calculate(currentVal, currentState.lastSecondOperand, currentState.lastOperator);
    if (repeatResult === null) {
      return Object.assign({}, INITIAL_STATE, {
        displayValue: '错误',
        isError: true
      });
    }
    var repeatDisplay = fixPrecision(repeatResult);
    return Object.assign({}, INITIAL_STATE, {
      displayValue: repeatDisplay,
      lastResult: repeatResult,
      lastOperator: currentState.lastOperator,
      lastSecondOperand: currentState.lastSecondOperand
    });
  }

  return currentState;
}

/**
 * 处理清除按钮
 * 
 * 行为：完全重置所有状态到初始值
 * 
 * @returns {Object} 初始状态
 */
function handleClear() {
  return Object.assign({}, INITIAL_STATE);
}

/**
 * 处理正负号切换
 * 
 * @param {Object} currentState - 当前状态
 * @returns {Object} 新状态
 */
function handleNegate(currentState) {
  if (currentState.waitingForSecondOperand) {
    return currentState;
  }
  var value = parseFloat(currentState.displayValue);
  var negated = -value;
  var displayValue = fixPrecision(negated);
  return Object.assign({}, currentState, {
    displayValue: displayValue
  });
}

/**
 * 处理百分比操作
 * 
 * @param {Object} currentState - 当前状态
 * @returns {Object} 新状态
 */
function handlePercent(currentState) {
  if (currentState.waitingForSecondOperand) {
    return currentState;
  }
  var value = parseFloat(currentState.displayValue);
  var percentValue = value / 100;
  var displayValue = fixPrecision(percentValue);
  return Object.assign({}, currentState, {
    displayValue: displayValue
  });
}

// ============================================================
// 初始化函数骨架（由 TASK-004 完善 DOM 绑定）
// ============================================================

/**
 * 初始化计算器
 * - 获取 DOM 元素引用
 * - 绑定按钮事件监听器
 * - 设置初始状态
 * 
 * 关联需求：REQ-NF003（纯 JS 事件绑定，无框架）
 * 
 * TODO: TASK-004 完善以下功能：
 * - 获取 #display, #expression, .keypad DOM 元素引用
 * - 在 .keypad 上绑定 click 事件委托
 * - 调用 updateDisplay() 和 updateOperatorHighlight() 渲染
 */
function init() {
  // TASK-004 将在此处添加 DOM 绑定逻辑
  state = Object.assign({}, INITIAL_STATE);
}

$content = Get-Content 'calculator/script.js' -Raw
$checks = @('INITIAL_STATE', 'function calculate', 'function fixPrecision', 'function handleAction', 'function inputDigit', 'function handleOperator', 'function handleEquals', 'function handleClear', 'isError', 'toFixed')
foreach ($check in $checks) {
    if ($content -match [regex]::Escape($check)) {
        Write-Host "PASS: Found $check"
    } else {
        Write-Host "FAIL: Missing $check"
    }
}

/* ============================================================
   Calculator Style Sheet
   深色主题计算器 - 类 iOS 风格
   ============================================================ */

/* --- CSS 自定义属性 --- */
:root {
  --btn-size: 80px;
  --color-bg: #1C1C1E;
  --color-digit: #333333;
  --color-operator: #FF9F0A;
  --color-function: #A5A5A5;
  --color-text-light: #FFFFFF;
  --color-text-dark: #1C1C1E;
  --color-text-gray: #A5A5A5;
}

/* --- 全局重置 --- */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background-color: var(--color-bg);
  color: var(--color-text-light);
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
  margin: 0;
  padding: 0;
}

/* --- 计算器容器 --- */
.calculator {
  max-width: 400px;
  width: 100%;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  padding: 20px;
}

/* --- 显示屏样式 --- */
.display {
  display: flex;
  flex-direction: column;
  justify-content: flex-end;
  align-items: flex-end;
  padding: 20px 24px;
  min-height: 120px;
  word-break: break-all;
  overflow: hidden;
}

.display-expression {
  color: var(--color-text-gray);
  font-size: 1.2rem;
  text-align: right;
  width: 100%;
  min-height: 1.4em;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.display-value {
  color: var(--color-text-light);
  font-size: clamp(2rem, 8vw, 3.5rem);
  font-weight: bold;
  text-align: right;
  width: 100%;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* --- 按钮网格 --- */
.keypad {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 12px;
  margin-top: 16px;
}

/* --- 通用按钮样式 --- */
.btn {
  height: var(--btn-size);
  border: none;
  border-radius: 50%;
  font-size: 1.8rem;
  font-weight: 500;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  touch-action: manipulation;
  transition: filter 0.1s ease;
  outline: none;
  -webkit-tap-highlight-color: transparent;
  user-select: none;
}

.btn:hover {
  filter: brightness(1.1);
}

.btn:active {
  filter: brightness(1.2);
}

/* --- 数字按钮 --- */
.btn-digit {
  background-color: var(--color-digit);
  color: var(--color-text-light);
}

/* --- 运算符按钮 --- */
.btn-operator {
  background-color: var(--color-operator);
  color: var(--color-text-dark);
  font-size: 2rem;
}

/* 运算符选中态：白底橙字 */
.btn-operator.active {
  background-color: var(--color-text-light);
  color: var(--color-operator);
}

/* --- 功能按钮 --- */
.btn-function {
  background-color: var(--color-function);
  color: #000000;
}

/* --- 等号按钮 --- */
.btn-equals {
  background-color: var(--color-operator);
  color: var(--color-text-dark);
  font-size: 2rem;
}

/* --- "0" 按钮跨列 --- */
.btn-zero {
  grid-column: span 2;
  border-radius: calc(var(--btn-size) / 2);
  justify-content: flex-start;
  padding-left: calc(var(--btn-size) * 0.35);
}

/* ============================================================
   响应式设计
   ============================================================ */

/* 手机端 (≤480px) */
@media (max-width: 480px) {
  :root {
    --btn-size: 15vmin;
  }

  .calculator {
    max-width: 100%;
    padding: 10px;
    min-height: 100vh;
    justify-content: flex-end;
  }

  .keypad {
    gap: 2vmin;
  }

  .display {
    padding: 16px 16px;
    min-height: 100px;
  }

  .btn {
    font-size: 5vmin;
  }

  .btn-operator,
  .btn-equals {
    font-size: 5.5vmin;
  }

  .display-expression {
    font-size: 3.5vmin;
  }
}

/* 平板/桌面端 (>480px) */
@media (min-width: 481px) {
  :root {
    --btn-size: 80px;
  }

  .calculator {
    max-width: 400px;
  }
}

