// ============================================================
// DOM 引用与渲染模块（design.md §6.2.4）
// ============================================================

/** DOM 元素引用缓存 */
var displayEl = null;     // #display
var expressionEl = null;  // #expression
var keypadEl = null;      // .keypad

/** 显示值长度阈值，超过后缩小字号 */
var DISPLAY_LENGTH_THRESHOLD = 9;

/**
 * 更新主显示屏内容
 * 
 * 同时根据内容长度动态调整字号，防止溢出
 * 
 * @param {string} displayValue - 要显示的值
 */
function updateDisplay(displayValue) {
  if (!displayEl) return;
  displayEl.textContent = displayValue;

  // 自适应字号：内容较长时缩小字体
  if (displayValue.length > DISPLAY_LENGTH_THRESHOLD) {
    var ratio = DISPLAY_LENGTH_THRESHOLD / displayValue.length;
    // 限制最小缩放比例为 0.5
    var scale = Math.max(ratio, 0.5);
    displayEl.style.fontSize = (2.2 * scale) + 'rem';
  } else {
    displayEl.style.fontSize = '';
  }
}

/**
 * 更新运算符按钮的高亮状态
 * 
 * 当某个运算符被选中时添加 .active class，其余移除
 * 
 * @param {string|null} activeOperator - 当前激活的运算符，null 时清除所有高亮
 */
function updateOperatorHighlight(activeOperator) {
  if (!keypadEl) return;
  var operatorBtns = keypadEl.querySelectorAll('.btn-operator');
  for (var i = 0; i < operatorBtns.length; i++) {
    var btn = operatorBtns[i];
    if (activeOperator && btn.dataset.operator === activeOperator) {
      btn.classList.add('active');
    } else {
      btn.classList.remove('active');
    }
  }
}

/**
 * 更新表达式行显示
 * 
 * 在运算符被选中时显示 "firstOperand operator"
 * 等号计算后显示完整表达式
 * 
 * @param {Object} currentState - 当前计算器状态
 * @param {string|null} expressionOverride - 可选的表达式覆盖文本（用于等号后完整表达式）
 */
function updateExpression(currentState, expressionOverride) {
  if (!expressionEl) return;

  if (expressionOverride) {
    expressionEl.textContent = expressionOverride;
    return;
  }

  if (currentState.firstOperand !== null && currentState.operator) {
    var firstStr = fixPrecision(currentState.firstOperand);
    expressionEl.textContent = firstStr + ' ' + currentState.operator;
  } else {
    expressionEl.textContent = '';
  }
}

// ============================================================
// 事件处理与交互模块（design.md §6.2.4）
// ============================================================

/**
 * 统一渲染函数：状态变更后同步更新 DOM
 * 
 * @param {string|null} expressionOverride - 可选的表达式覆盖文本
 */
function render(expressionOverride) {
  updateDisplay(state.displayValue);
  updateOperatorHighlight(state.waitingForSecondOperand ? state.operator : null);
  updateExpression(state, expressionOverride || null);
}

/**
 * 事件委托处理器：根据按钮的 data-action 属性分发操作
 * 
 * 读取 data-digit 获取数字值，data-operator 获取运算符
 * 构造 action 对象调用 handleAction() 并触发渲染
 * 
 * @param {Event} event - click 事件对象
 */
function handleKeypadClick(event) {
  var target = event.target;

  // 确保点击的是按钮元素（排除 keypad 容器本身的点击）
  if (!target.dataset.action) return;

  var actionType = target.dataset.action;
  var action = null;

  switch (actionType) {
    case 'digit':
      action = { type: 'DIGIT', value: target.dataset.digit };
      break;
    case 'operator':
      action = { type: 'OPERATOR', operator: target.dataset.operator };
      break;
    case 'equals':
      action = { type: 'EQUALS' };
      break;
    case 'clear':
      action = { type: 'CLEAR' };
      break;
    case 'negate':
      action = { type: 'NEGATE' };
      break;
    case 'percent':
      action = { type: 'PERCENT' };
      break;
    default:
      return;
  }

  // 记录等号前的状态，用于生成完整表达式
  var expressionOverride = null;
  if (actionType === 'equals' && state.firstOperand !== null && state.operator && !state.waitingForSecondOperand) {
    var firstStr = fixPrecision(state.firstOperand);
    var secondStr = state.displayValue;
    expressionOverride = firstStr + ' ' + state.operator + ' ' + secondStr + ' =';
  }

  state = handleAction(state, action);
  render(expressionOverride);
}

// ============================================================
// 初始化函数（design.md §6.2.4, REQ-NF003）
// ============================================================

/**
 * 初始化计算器
 * - 获取 DOM 元素引用
 * - 绑定按钮事件监听器
 * - 设置初始状态
 * 
 * 关联需求：REQ-NF003（纯 JS 事件绑定，无框架）
 */
function init() {
  // 获取 DOM 元素引用
  displayEl = document.getElementById('display');
  expressionEl = document.getElementById('expression');
  keypadEl = document.querySelector('.keypad');

  // 初始化状态
  state = Object.assign({}, INITIAL_STATE);

  // 在 .keypad 容器上绑定事件委托
  if (keypadEl) {
    keypadEl.addEventListener('click', handleKeypadClick);
  }

  // 首次渲染
  render();
}

// ============================================================
// 启动：DOMContentLoaded 时初始化
// ============================================================

document.addEventListener('DOMContentLoaded', init);

